js_content = """// ============================================================
// Boids Flocking Simulation
// Implements Craig Reynolds' Boids algorithm with:
//   - Separation, Alignment, Cohesion
//   - Spatial hashing for performance
//   - Mouse interaction (attract/repel)
//   - Trails, wrap/bounce edges, predator mode
// ============================================================

const canvas = document.getElementById('canvas');
const ctx = canvas.getContext('2d');

// --- Resize ---
function resize() {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
}
window.addEventListener('resize', resize);
resize();

// --- Parameters ---
const params = {
    count: 200,
    separation: 1.5,
    alignment: 1.0,
    cohesion: 1.0,
    visualRange: 75,
    maxSpeed: 4,
    minSpeed: 1.5,
    trail: 0,
    predator: false,
    wrapEdges: true,
    margin: 100,
    turnFactor: 0.3,
};

let paused = false;
let mouse = { x: -9999, y: -9999, active: false };

// --- Mouse tracking ---
canvas.addEventListener('mousemove', (e) => {
    mouse.x = e.clientX;
    mouse.y = e.clientY;
    mouse.active = true;
});
canvas.addEventListener('mouseleave', () => {
    mouse.active = false;
});

// --- Boid class ---
class Boid {
    constructor(x, y) {
        this.x = x;
        this.y = y;
        const angle = Math.random() * Math.PI * 2;
        const speed = params.minSpeed + Math.random() * (params.maxSpeed - params.minSpeed);
        this.vx = Math.cos(angle) * speed;
        this.vy = Math.sin(angle) * speed;
        // Color hue based on initial angle
        this.hue = (angle / (Math.PI * 2)) * 360;
        this.history = [];
    }
}

// --- Spatial Hash Grid ---
class SpatialGrid {
    constructor(cellSize) {
        this.cellSize = cellSize;
        this.grid = new Map();
    }

    clear() {
        this.grid.clear();
    }

    _key(cx, cy) {
        return cx * 73856093 ^ cy * 19349663;
    }

    insert(boid) {
        const cx = Math.floor(boid.x / this.cellSize);
        const cy = Math.floor(boid.y / this.cellSize);
        const key = this._key(cx, cy);
        if (!this.grid.has(key)) {
            this.grid.set(key, []);
        }
        this.grid.get(key).push(boid);
    }

    query(boid, range) {
        const results = [];
        const cr = Math.ceil(range / this.cellSize);
        const cx = Math.floor(boid.x / this.cellSize);
        const cy = Math.floor(boid.y / this.cellSize);
        const rangeSq = range * range;

        for (let dx = -cr; dx <= cr; dx++) {
            for (let dy = -cr; dy <= cr; dy++) {
                const key = this._key(cx + dx, cy + dy);
                const cell = this.grid.get(key);
                if (!cell) continue;
                for (let i = 0; i < cell.length; i++) {
                    const other = cell[i];
                    if (other === boid) continue;
                    const ddx = other.x - boid.x;
                    const ddy = other.y - boid.y;
                    if (ddx * ddx + ddy * ddy < rangeSq) {
                        results.push(other);
                    }
                }
            }
        }
        return results;
    }
}

// --- Flock ---
let boids = [];
let grid = new SpatialGrid(params.visualRange);

function initBoids(count) {
    boids = [];
    for (let i = 0; i < count; i++) {
        boids.push(new Boid(
            Math.random() * canvas.width,
            Math.random() * canvas.height
        ));
    }
}
initBoids(params.count);

// --- Boid rules ---
function applyRules(boid, neighbors) {
    let sepX = 0, sepY = 0;
    let alignX = 0, alignY = 0;
    let cohX = 0, cohY = 0;
    const n = neighbors.length;

    if (n === 0) return;

    const separationDist = params.visualRange * 0.4;
    const sepDistSq = separationDist * separationDist;

    for (let i = 0; i < n; i++) {
        const other = neighbors[i];
        const dx = boid.x - other.x;
        const dy = boid.y - other.y;
        const distSq = dx * dx + dy * dy;

        // Separation - avoid crowding
        if (distSq < sepDistSq && distSq > 0) {
            const dist = Math.sqrt(distSq);
            sepX += (dx / dist) / dist;
            sepY += (dy / dist) / dist;
        }

        // Alignment - steer towards average heading
        alignX += other.vx;
        alignY += other.vy;

        // Cohesion - steer toward average position
        cohX += other.x;
        cohY += other.y;
    }

    // Separation
    boid.vx += sepX * params.separation * 2;
    boid.vy += sepY * params.separation * 2;

    // Alignment
    alignX /= n;
    alignY /= n;
    boid.vx += (alignX - boid.vx) * params.alignment * 0.05;
    boid.vy += (alignY - boid.vy) * params.alignment * 0.05;

    // Cohesion
    cohX /= n;
    cohY /= n;
    boid.vx += (cohX - boid.x) * params.cohesion * 0.005;
    boid.vy += (cohY - boid.y) * params.cohesion * 0.005;
}

function applyEdgeBehavior(boid) {
    if (params.wrapEdges) {
        // Wrap around
        if (boid.x < 0) boid.x += canvas.width;
        if (boid.x > canvas.width) boid.x -= canvas.width;
        if (boid.y < 0) boid.y += canvas.height;
        if (boid.y > canvas.height) boid.y -= canvas.height;
    } else {
        // Turn away from edges
        const m = params.margin;
        const t = params.turnFactor;
        if (boid.x < m) boid.vx += t;
        if (boid.x > canvas.width - m) boid.vx -= t;
        if (boid.y < m) boid.vy += t;
        if (boid.y > canvas.height - m) boid.vy -= t;
    }
}

function applyMouseInteraction(boid) {
    if (!mouse.active) return;
    const dx = boid.x - mouse.x;
    const dy = boid.y - mouse.y;
